#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-06

# Token-set scan: every fenced ASCII block in src/skills/**/SKILL.md must
# use glyphs from exactly ONE token set (or zero box-drawing chars).
# Mirrors the ascii-lint `single-set` rule but runs as static CI, not
# PostToolUse вАФ catches cross-file consistency drift.

set -euo pipefail

ROOT="$(cd "$(dirname "$0")/../.." && pwd)"
SKILLS_DIR="$ROOT/src/skills"

# Set definitions (glyphs per set). Mirrors src/hooks/src/posttool/ascii-lint.ts.
SET_DEFAULT='вФМвФРвФФвФШ'
SET_EMPHASIS='вФПвФУвФЧвФЫвФБвФГвФ≥вФївФ£вФЂвХЛ'
SET_TITLE='вХФвХЧвХЪвХЭвХРвХСвХ¶вХ©вХ†вХ£вХђ'
SET_SOFT='вХ≠вХЃвХ∞вХѓ'

fail=0
checked=0

contains_any() {
  local text="$1" chars="$2" ch
  local i=0
  while [ $i -lt ${#chars} ]; do
    ch="${chars:$i:1}"
    case "$text" in *"$ch"*) return 0 ;; esac
    i=$((i + 1))
  done
  return 1
}

scan_block() {
  local file="$1" startline="$2" block="$3"
  local found=()
  if contains_any "$block" "$SET_DEFAULT";  then found+=("default");  fi
  if contains_any "$block" "$SET_EMPHASIS"; then found+=("emphasis"); fi
  if contains_any "$block" "$SET_TITLE";    then found+=("title");    fi
  if contains_any "$block" "$SET_SOFT";     then found+=("soft");     fi
  if [ ${#found[@]} -gt 1 ]; then
    printf 'вЬЧ %s:%d mixes sets: %s\n' "${file#$ROOT/}" "$startline" "${found[*]}"
    fail=$((fail + 1))
  fi
}

# Count Unicode Box-Drawing chars (U+2500-U+257F). python3 always exits 0.
count_box() {
  printf '%s' "$1" | python3 -c '
import sys
print(sum(1 for c in sys.stdin.read() if 0x2500 <= ord(c) <= 0x257F))
'
}

scan_file() {
  local file="$1"
  local in_block=0
  local block=""
  local startline=0
  local lineno=0
  local pending_disable=""
  while IFS= read -r line; do
    lineno=$((lineno + 1))
    if [ "$in_block" = 0 ]; then
      case "$line" in
        *'<!-- ascii-lint-disable:'*)
          pending_disable=$(printf '%s' "$line" | sed -E 's/.*ascii-lint-disable:[[:space:]]*([^[:space:]>-]+([,[:space:]-]+[^[:space:]>-]+)*).*/\1/')
          ;;
        '```'*) in_block=1; block=""; startline=$((lineno + 1)) ;;
      esac
    else
      case "$line" in
        '```'*)
          local box_count
          box_count=$(count_box "$block")
          if [ "${box_count:-0}" -ge 3 ]; then
            checked=$((checked + 1))
            case ",$pending_disable," in
              *,single-set,*) : ;;
              *) scan_block "$file" "$startline" "$block" ;;
            esac
          fi
          in_block=0
          pending_disable=""
          ;;
        *) block+="$line"$'\n' ;;
      esac
    fi
  done < "$file"
}

for file in "$SKILLS_DIR"/*/SKILL.md; do
  [ -f "$file" ] || continue
  scan_file "$file"
done

printf '\nвЬУ scanned %d block(s) ¬Ј вЬЧ %d failure(s)\n' "$checked" "$fail"
# Advisory by default (matches D3 lint hook severity). Opt-in enforcement:
if [ "${ASCII_TOKENS_BLOCK:-0}" = "1" ] && [ "$fail" -gt 0 ]; then
  exit 1
fi
exit 0
